import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'

const HERO = 'data:image/jpeg;base64,'

export default function Login() {
  const { signIn } = useAuth()
  const navigate = useNavigate()
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState(null)
  const [loading, setLoading] = useState(false)

  const handleSubmit = async (e) => {
    e.preventDefault()
    setLoading(true)
    setError(null)
    const { error } = await signIn(email, password)
    if (error) {
      setError(error.message)
      setLoading(false)
    } else {
      navigate('/dashboard')
    }
  }

  return (
    <div style={{ minHeight: '100dvh', background: '#000', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden', position: 'relative' }}>

      {/* Background image — cover on all devices, no distortion */}
      <div
        style={{
          position: 'fixed',
          inset: 0,
          zIndex: 0,
          backgroundImage: `url('${HERO}')`,
          backgroundSize: 'cover',
          backgroundPosition: 'center top',
          backgroundRepeat: 'no-repeat',
        }}
      />

      {/* Dark overlay */}
      <div
        style={{
          position: 'fixed',
          inset: 0,
          zIndex: 1,
          background: 'rgba(0,0,0,0.62)',
        }}
      />

      {/* Main content — centered, mobile-safe padding */}
      <div style={{
        position: 'relative',
        zIndex: 2,
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        width: '100%',
        maxWidth: '420px',
        padding: '2rem 1.25rem',
        margin: '0 auto',
      }}>

        {/* Brand */}
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: '2rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
            <svg width="38" height="32" viewBox="0 0 46 38" fill="none">
              <polygon points="0,36 16,2 22,14 9,36" fill="white"/>
              <polygon points="13,36 26,8 32,22 20,36" fill="white" opacity="0.62"/>
              <polygon points="20,36 30,18 34,28 22,36" fill="white" opacity="0.32"/>
            </svg>
            <div style={{ width: '1px', height: '38px', background: 'rgba(255,255,255,0.35)' }} />
            <span style={{ color: 'white', fontWeight: 900, fontSize: 'clamp(1.8rem, 8vw, 2.8rem)', letterSpacing: '0.18em', textTransform: 'uppercase', lineHeight: 1, fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>AXIOS</span>
          </div>
          <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.6rem', letterSpacing: '0.42em', textTransform: 'uppercase', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>I Am Worthy</p>
        </div>

        {/* Tagline */}
        <div style={{ textAlign: 'center', marginBottom: '1.75rem' }}>
          <p style={{ color: 'rgba(255,255,255,0.28)', fontSize: '0.6rem', letterSpacing: '0.25em', textTransform: 'uppercase', marginBottom: '6px', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>Est. 1989</p>
          <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: 'clamp(0.85rem, 3vw, 0.95rem)', fontWeight: 300, lineHeight: 1.6, fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>
            Discipline. Accountability. Personal ownership.
          </p>
        </div>

        {/* Form card */}
        <form
          onSubmit={handleSubmit}
          style={{
            width: '100%',
            background: 'rgba(255,255,255,0.06)',
            border: '0.5px solid rgba(255,255,255,0.15)',
            borderRadius: '2px',
            padding: 'clamp(1.25rem, 5vw, 2rem)',
            backdropFilter: 'blur(12px)',
            WebkitBackdropFilter: 'blur(12px)',
          }}
        >
          <p style={{ color: 'rgba(255,255,255,0.3)', fontSize: '0.6rem', letterSpacing: '0.3em', textTransform: 'uppercase', marginBottom: '1.25rem', textAlign: 'center', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>
            Secure Access
          </p>

          {/* Email */}
          <div style={{ marginBottom: '1rem' }}>
            <label style={{ display: 'block', color: 'rgba(255,255,255,0.4)', fontSize: '0.6rem', letterSpacing: '0.22em', textTransform: 'uppercase', marginBottom: '6px', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>Email</label>
            <input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="your@email.com"
              required
              style={{
                width: '100%',
                boxSizing: 'border-box',
                background: 'rgba(255,255,255,0.06)',
                border: '0.5px solid rgba(255,255,255,0.18)',
                borderRadius: '2px',
                color: 'white',
                padding: '12px 14px',
                fontSize: '1rem',
                fontFamily: '"Helvetica Neue", Helvetica, sans-serif',
                outline: 'none',
                WebkitAppearance: 'none',
              }}
            />
          </div>

          {/* Password */}
          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', color: 'rgba(255,255,255,0.4)', fontSize: '0.6rem', letterSpacing: '0.22em', textTransform: 'uppercase', marginBottom: '6px', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>Password</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="••••••••••"
              required
              style={{
                width: '100%',
                boxSizing: 'border-box',
                background: 'rgba(255,255,255,0.06)',
                border: '0.5px solid rgba(255,255,255,0.18)',
                borderRadius: '2px',
                color: 'white',
                padding: '12px 14px',
                fontSize: '1rem',
                fontFamily: '"Helvetica Neue", Helvetica, sans-serif',
                outline: 'none',
                WebkitAppearance: 'none',
              }}
            />
          </div>

          {error && (
            <p style={{ color: 'rgba(255,100,100,0.85)', fontSize: '0.75rem', marginBottom: '1rem', textAlign: 'center', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>{error}</p>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            style={{
              width: '100%',
              background: 'white',
              color: 'black',
              border: 'none',
              borderRadius: '2px',
              padding: '14px',
              fontSize: '0.72rem',
              fontWeight: 800,
              letterSpacing: '0.3em',
              textTransform: 'uppercase',
              cursor: 'pointer',
              fontFamily: '"Helvetica Neue", Helvetica, sans-serif',
              opacity: loading ? 0.5 : 1,
              WebkitAppearance: 'none',
            }}
          >
            {loading ? 'Entering...' : 'Enter'}
          </button>

          <p style={{ color: 'rgba(255,255,255,0.18)', fontSize: '0.58rem', letterSpacing: '0.15em', textTransform: 'uppercase', textAlign: 'center', marginTop: '1.1rem', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>
            Authorized access only
          </p>
        </form>

        <p style={{ color: 'rgba(255,255,255,0.2)', fontSize: '0.55rem', letterSpacing: '0.15em', textTransform: 'uppercase', marginTop: '1.5rem', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>
          "Axios" — I am worthy
        </p>
      </div>

      {/* Est footer */}
      <p style={{
        position: 'fixed',
        bottom: '1.5rem',
        left: '1.5rem',
        color: 'rgba(255,255,255,0.18)',
        fontSize: '0.55rem',
        letterSpacing: '0.22em',
        textTransform: 'uppercase',
        fontStyle: 'italic',
        zIndex: 2,
        fontFamily: '"Helvetica Neue", Helvetica, sans-serif',
      }}>
        Est 1989
      </p>
    </div>
  )
}
